#include <stdio.h>
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int m, x, y;
        scanf("%d %d %d", &m, &x, &y);
        int houses[100] = {0};
        for (int i = 0; i < m; i++) {
            int copHouse;
            scanf("%d", &copHouse);
            for (int j = copHouse - x * y; j <= copHouse + x * y; j++) {
                if (j >= 1 && j <= 100) {
                    houses[j - 1] = 1;
                }
            }
        }
        int count = 0;
        for (int i = 0; i < 100; i++) {
            if (houses[i] == 0) {
                count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

